mapper.select:
select s.HOST from SESSIONS s
where 1 = 1
and s.ID = #{sessionId}

mapper.delete:
DELETE FROM table_assignments
WHERE 1 = 1
AND session_id = #{sessionId}

mapper.update:
UPDATE TABLE_ASSIGNMENTS
SET TABLE_NO = CASE

    WHEN SESSION_ID = #{sessionId}
    AND USER_ID = #{item.userId}
    AND ROUND_NO = #{item.roundNo}
    THEN #{item.tableNo}

ELSE TABLE_NO
END
WHERE SESSION_ID = #{sessionId}
AND (

    (USER_ID = #{item.userId} AND ROUND_NO = #{item.roundNo})

)
